external_knowledge:
- 'anchors' refers to the customers who have applied for loans; 
- 'lifeboats' symbolize the collateral provided by these customers;
- the 'stormy sea of loan applications' metaphorically represents the environment of loan applications, where providing collateral is akin to a protective measure in challenging financial conditions.

sql:
SELECT la.application_id, la.customer_id, cs.credit_score
FROM loan_applications la
LEFT JOIN credit_scores cs ON la.customer_id = cs.customer_id;

SELECT customer_id, COUNT(application_id) AS loan_application_count, AVG(loan_amount) AS average_loan_amount
FROM loan_applications
GROUP BY customer_id;

SELECT AVG(cs.credit_score) AS average_credit_score
FROM credit_scores cs
INNER JOIN loan_applications la ON cs.customer_id = la.customer_id;

SELECT COUNT(*) AS total_credit_scores, 
       AVG(credit_score) AS average_credit_score 
FROM credit_scores;

SELECT COUNT(*) AS total_documents
FROM loan_application_documents
WHERE application_id = 'specific_application_id';

SELECT application_id, FLOOR(loan_amount) AS rounded_loan_amount
FROM loan_applications
ORDER BY rounded_loan_amount DESC;

SELECT application_channel, COUNT(*) AS number_of_applications
FROM loan_applications
GROUP BY application_channel;
